static void tvsub(struct timeval *t1, struct timeval *t0, struct timeval *td)
{
    td->tv_sec = t1->tv_sec - t0->tv_sec;
    td->tv_usec = t1->tv_usec - t0->tv_usec;
    if (td->tv_usec < 0) {
        td->tv_sec--;
        td->tv_usec += 1000000;
    }
}
#endif

static int initialize()
{
