}

int maximum(int a, int b, int c)
{
    int k;
    if (a <= b)
        k = b;
    else
        k = a;

    if (k <= c)
        return c;
    else
        return k;
}

void usage(int argc, char **argv)
{
    fprintf(stderr, "Usage: %s <max_rows/max_cols> <penalty> [-p platform] [-d device]\n", argv[0]);
    fprintf(stderr, "\t<dimension>  - x and y dimensions\n");
    fprintf(stderr, "\t<penalty> - penalty(positive integer)\n");
    fprintf(stderr, "\t<file> - filename\n");
    fprintf(stderr, "\t[platform] - platform id\n");
    fprintf(stderr, "\t[device] - device id\n");
    exit(1);
}

double gettime()
{
    struct timeval t;
    gettimeofday(&t, NULL);
    return t.tv_sec + t.tv_usec * 1e-6;
}

static inline void process_block(const int *reference, int *input_itemsets, int cols, int penalty,
                                 int b_index_y, int b_index_x, int base)
{
    int start = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;

    for (int i = 1; i <= BLOCK_SIZE; i++) {
        int row_base = start + i * cols;
        for (int j = 1; j <= BLOCK_SIZE; j++) {
            int idx = row_base + j;
            input_itemsets[idx] = maximum(input_itemsets[idx - cols - 1] + reference[idx],
                                          input_itemsets[idx - 1] - penalty,
                                          input_itemsets[idx - cols] - penalty);
        }
    }
}

